1	import { defineStore } from 'pinia'
2	import { ref, computed } from 'vue'
3	import api from '../api/index.js'
4	
5	export const useAuthStore = defineStore('auth', () => {
6	  const user = ref(null)
7	  const accessToken = ref(localStorage.getItem('access_token') || null)
8	  const refreshToken = ref(localStorage.getItem('refresh_token') || null)
9	
10	  const isAuthenticated = computed(() => !!accessToken.value)
11	  const userRole = computed(() => user.value?.role || null)
12	
13	  function isRole(...roles) {
14	    return roles.includes(userRole.value)
15	  }
16	
17	  async function login(username, password) {
18	    const response = await api.post('/auth/login', { username, password })
19	    const { access_token, refresh_token } = response.data
20	    accessToken.value = access_token
21	    refreshToken.value = refresh_token
22	    localStorage.setItem('access_token', access_token)
23	    localStorage.setItem('refresh_token', refresh_token)
24	    await fetchUser()
25	  }
26	
27	  async function logout() {
28	    try {
29	      if (refreshToken.value) {
30	        await api.post('/auth/logout', { refresh_token: refreshToken.value })
31	      }
32	    } catch {
33	      // Proceed with local logout even if server call fails
34	    } finally {
35	      accessToken.value = null
36	      refreshToken.value = null
37	      user.value = null
38	      localStorage.removeItem('access_token')
39	      localStorage.removeItem('refresh_token')
40	    }
41	  }
42	
43	  async function fetchUser() {
44	    try {
45	      const response = await api.get('/users/me')
46	      user.value = response.data
47	    } catch {
48	      user.value = null
49	    }
50	  }
51	
52	  async function refreshTokens() {
53	    if (!refreshToken.value) return false
54	    try {
55	      const response = await api.post('/auth/refresh', {
56	        refresh_token: refreshToken.value,
57	      })
58	      const { access_token, refresh_token } = response.data
59	      accessToken.value = access_token
60	      refreshToken.value = refresh_token
61	      localStorage.setItem('access_token', access_token)
62	      localStorage.setItem('refresh_token', refresh_token)
63	      return true
64	    } catch {
65	      return false
66	    }
67	  }
68	
69	  async function init() {
70	    if (accessToken.value) {
71	      await fetchUser()
72	    }
73	  }
74	
75	  return {
76	    user,
77	    accessToken,
78	    refreshToken,
79	    isAuthenticated,
80	    userRole,
81	    isRole,
82	    login,
83	    logout,
84	    fetchUser,
85	    refreshTokens,
86	    init,
87	  }
88	})
