import { ref } from 'vue'

const CACHE_PREFIX = 'tc_cache_'
const DEFAULT_TTL_MS = 5 * 60 * 1000  // 5 minutes

export const useOfflineStore = defineStore('offline', () => {
  const isOnline = ref(navigator.onLine)

  window.addEventListener('online',  () => { isOnline.value = true  })
  window.addEventListener('offline', () => { isOnline.value = false })

  function cacheSet(key, data, ttlMs = DEFAULT_TTL_MS) {
    try {
      localStorage.setItem(CACHE_PREFIX + key, JSON.stringify({
        data, expiresAt: Date.now() + ttlMs,
      }))
    } catch { /* storage full — ignore */ }
  }

  function cacheGet(key) {
    try {
      const raw = localStorage.getItem(CACHE_PREFIX + key)
      if (!raw) return null
      const { data, expiresAt } = JSON.parse(raw)
      if (Date.now() > expiresAt) { localStorage.removeItem(CACHE_PREFIX + key); return null }
      return data
    } catch { return null }
  }

  function cacheClear(key) {
    localStorage.removeItem(CACHE_PREFIX + key)
  }

  function cacheClearAll() {
    Object.keys(localStorage)
      .filter(k => k.startsWith(CACHE_PREFIX))
      .forEach(k => localStorage.removeItem(k))
  }

  /** Fetch with automatic offline fallback to cache. */
  async function fetchWithCache(key, fetcher, ttlMs = DEFAULT_TTL_MS) {
    if (isOnline.value) {
      try {
        const data = await fetcher()
        cacheSet(key, data, ttlMs)
        return { data, fromCache: false }
      } catch (err) {
        const cached = cacheGet(key)
        if (cached) return { data: cached, fromCache: true }
        throw err
      }
    } else {
      const cached = cacheGet(key)
      if (cached) return { data: cached, fromCache: true }
      throw new Error('Offline and no cached data available')
    }
  }

  return { isOnline, cacheSet, cacheGet, cacheClear, cacheClearAll, fetchWithCache }
})
"}

