  router.beforeEach((to, _from, next) => {
    if (to.meta.requiresAuth && !isAuthenticated) {
      return next({ name: 'Login', query: { redirect: to.fullPath } })
    }
    if (to.meta.requiresGuest && isAuthenticated) {
      return next({ name: 'Dashboard' })
    }
    next()
  })

  return router
}

